def init (main : Unit) : Nat := 0

def overflow : Prop := ∀ n : Nat, n < 3

def G' (P : Prop) : Prop := ∀ s : Stream Nat, ∀ i : Nat, P i → P (s.push i)

def G (P : Prop) : Prop := ∀ (s : Stream Nat), ∀ i : Nat, P i → P (s.push i)

def LTL (p : Prop) : Prop := ∀ (s : Stream Prop), p (last s) ∧ G' p s

def main : Unit := do
  let f' (n : Nat) : Nat := if n < 3 then 0 else (n - 1)
  let rec loop (n : Nat) : Stream Nat := if n < 3 then stream.empty else (stream.cons n (loop (f' n)))
  let s : Stream Nat := loop 2
  let h : Prop := ∀ i, i < (s.length) → i < 3
