set_option pp.all false

def init (main : Unit) : Unit := do
  let x := ∫ 0 < n < 99, if hNat.even n then 2 else 1
  let y := ∫ i := 0, ℕ.choose
  let h := ∀ (hx : Nat), x + hx = ℕ.sum (finset.range 99) fun i => if hNat.even i then 2 else 1
  let hy := hNat.even y
  let hx := hNat.even x
  return match (hx, hy) with
  | (true, true) => pure unit
  | (false, false) => fail "assertion failed"

def reach_error () : Unit := fail "reach_error"

def call (f : Unit → Unit) : Unit := do
  let old_exit := Lean.Control.setExitOnError false in
  f ()
  Lean.Control.setExitOnError old_exit

def G' (p : Prop) : Prop := ∀ s : Stream Prop, ∀ i : Nat, p (s.get i) → p (s.get (i + 1))

def G (p : Prop) : Prop := ∃ (s : Stream Prop), G' p s

def LTL (p : Prop) : Prop := ∀ (s : Stream Prop), ∀ i : Nat, p (s.get i) → p (s.get (i + 1)) → p (s.get (i + 2)) → ... → p (s.get (i + n))
  where n := 10

def main () : Unit := do
  let x := ℕ.mkNat 0
  let y := ℕ.mkNat <| ℕ.choose
  let mut n := x
  while (x < 99) do
    let h := hNat.even x
    match h with
    | true => do
      x := x + 2
    | false => do
      x := x + 1
    let h := hNat.even y
    n := n + 1
  let hx := hNat.even x
  let hy := hNat.even y
  let h := hx = hy
  let s := Stream.cons hx <| Stream.cons hy <| Stream.repeat (hNat.even)
  let p := G' (hNat.even) s
