import Mathlib

open Lean.Elab.Tactics
open Lean.Parser.Tactics

def init := λ _, do
  let input ← pure <| randomInt.sample (nat.succ ⁡ maxInt)
  id input

def id (x : ℕ) : ℕ :=
if hx : x = 0 then 0
else do {
  let hx' ← getMonadicLocalState
  let hx'' := id (x - 1)
  let hx''' ← setMonadicLocalState hx''
  pure (hx''' + 1)
} else
if hx > 5 then pure 5
else pure hx

def call (reach\_error : Unit → Unit) : Prop :=
false

def G' : Prop := ∀ (s : StateM ℕ Unit), ∀ (x : ℕ), s >>= fun _ => id x >>= fun _ => pure (G' s x)

def G : Prop := ∀ (s : StateM ℕ Unit), G' s

def LTL (p : Prop) : Prop := ∀ (s : StateM ℕ Unit), ∀ (n : ℕ), p s >>= fun _ => n < nat.succ ⁡ maxInt >>= fun _ => pure (p s)

def check : Prop → Prop := λ p, init >>= fun _ => p

check (G (call reach\_error)) (LTL (neg (call reach\_error)))

import Mathlib

open Lean Nat

def fibonacci (n : Nat) : Nat :=
if hNat.zero? n then 0
else if hNat.succ_eq_zero n then 1
else fibonacci (hNat.pred n) + fibonacci (hNat.pred (hNat.pred n))

def init' : IO Unit := do
  let x ← randomNat 47 -- assuming the C code uses a random number up to 46
  return ()

def main' : IO Unit := do
  let x ← randomNat 47
  let result := fibonacci x
  let cond := x != 5 ∧ result ≠ 3
  if cond then return () else fail "reach_error"

def check : IO Unit := do
  let _ ← init'
  let ℳ := ∀ (s : StateM IO Unit), ∀ (p : Prop), match s.run () with
    | .ok _ => p
