  let mut sum : Array (Int64) := [0]
  let mut a : Array (Int64) := <| Array.fill ⁱ N 1
  let sum' : Int64 := sum.foldM (λ i acc, acc + a.get! i) 0
  let a' : Array (Int64) := a.mapM (λ i, a.get! i + sum')
  sum := sum.map (λ i, i + a'.foldl (λ acc i, acc + i) 0)
  assume (∀ i, a'.get! i = (N + 1) * (N + 1))
  pure unit

