open Lean.Elab.Tactics
open Lean.Elab.Attributes
open Lean.Elab.Expression
open Lean.Elab.Term
open Lean.Parser.Tactics
open Lean.Parser.Term

namespace Main

def init := do
  let N_LIN ← expression.const `__VERIFIER_nondet_uint`
  let N_COL ← expression.const `__VERIFIER_nondet_uint`
  let maior ← expression.const `__VERIFIER_nondet_int`
  let matriz := Array.mapM (fun j => Array.mapM (fun k => do
      let matriz_ij ← expression.const <| expression.app `matriz j k
      return matriz_ij
  )) (range N_COL)
  let j := expression.const `j
  let k := expression.const `k
  let G_valid_free := ∀ i j, matriz i j < maior
  let G_valid_deref := ∀ i, ∀ j, matriz i j = (Array.get matriz i j)
  let G_valid_memtrack := ∀ i j, ∃! k, i = k ∧ j = k ∨ (i < k ∧ j < k) ∨ (i = k ∧ j > k) ∨ (i > k ∧ j = k)
  let valid_free := ∀ i j, matriz i j < maior
  let valid_deref := ∀ i, ∀ j, matriz i j = (Array.get matriz i j)
  let valid_memtrack := ∀ i j, ∃! k, i = k ∧ j = k ∨ (i < k ∧ j < k) ∨ (i = k ∧ j > k) ∨ (i > k ∧ j = k)
  let assert_valid_free := λ _, do
    let ⊢ _ ← tactic.assume valid_free
    tactic.skip
  let assert_valid_deref := λ _, do
    let ⊢ _ ← tactic.assume valid_deref
    tactic.skip
  let assert_valid_memtrack := λ _, do
    let ⊢ _ ← tactic.assume valid_memtrack
    tactic.skip
  let main := do
    let _ ← tactic.assume init
    let _ ← tactic.repeat (fun i => do
      let _ ← tactic.assume (j ∈ range N_COL)
      let _ ← tactic.assume (k ∈ range N_LIN)
      let matriz_ij ← Array.get matriz j k
      let _ ← tactic.assert (matriz_ij < maior) using [| valid_free |]
    ))
    return ()
  let _ ← tactic.repeat (fun i => do
    let _ ← tactic.assume (j ∈ range N_COL)
    let _ ← tactic.assume (k ∈ range N_LIN)
    let matriz_ij ← Array.get matriz j k
    let _ ← tactic.assert (matriz_ij = (Array.get matriz j k)) using [| valid_deref |]
  ))
  let _ ← tactic.repeat (fun i => do
    let _ ← tactic.assume (j ∈ range N_COL)
    let _ ← tactic.assume (k ∈ range N_LIN)
    let _ ← tactic.assert (∃! l i, l = i ∨ (l < i ∧ j < i) ∨ (l = i ∧ j > i) ∨ (l > i ∧ j = i) ∨ (l > i ∧ j < i)) using [| valid_memtrack |]
  ))
  let _ ← tactic.repeat (fun i => do
    let _ ← tactic.assume (j ∈ range N_COL)
    let _ ← tactic.assume (k ∈ range N_LIN)
    let matriz_ij ← Array.get matriz j k
    let _ ← tactic.assert (matriz_ij < maior) using [| valid_free |]
  ))
  let _ ← tactic.repeat (fun i => do
    let _ ← tactic.assume (j ∈ range N_COL)
    let _ ← tactic.assume (k ∈ range N_LIN)
    let matriz_ij ← Array.get matriz j k
    let _ ← tactic.assert (matriz_ij = (Array.get matriz j k)) using [| valid_deref |]
  ))
  let _ ← tactic.repeat (fun i => do
    let _ ← tactic.assume (j ∈ range N_COL)
    let _ ← tactic.assume (k ∈ range N_LIN)
    let _ ← tactic.assert (∃! l i, l = i ∨ (l < i ∧ j < i) ∨ (l = i ∧ j > i) ∨ (l > i ∧ j = i) ∨ (l > i ∧ j < i)) using [| valid_memtrack |]
  ))
  let _ ← tactic.qed
  return ()

